SELECT DISTINCT date, CAST(EXTRACT(year FROM date) AS INTEGER) AS year, CAST(EXTRACT(month FROM date) AS INTEGER) AS month, uf_origem, uf_destino, produto, classificacao, sub_classificacao, operacao, modal, qtd_produto_liquido FROM (SELECT make_date(TRY_CAST(split_part(trim("periodo"), '/', 1) AS INTEGER), TRY_CAST(split_part(trim("periodo"), '/', 2) AS INTEGER), 1) AS date, NULLIF(TRIM("uf_origem"), '') AS uf_origem, NULLIF(TRIM("uf_destino"), '') AS uf_destino, NULLIF(TRIM("produto"), '') AS produto, NULLIF(TRIM("classificacao"), '') AS classificacao, NULLIF(TRIM("sub_classificacao"), '') AS sub_classificacao, NULLIF(TRIM("operacao"), '') AS operacao, NULLIF(TRIM("modal"), '') AS modal, TRY_CAST(replace(replace(trim("qtd_produto_liquido"), '.', ''), ',', '.') AS DOUBLE) AS qtd_produto_liquido FROM "anp-brazil-mdpg-movimentacaologistica") WHERE date IS NOT NULL AND (qtd_produto_liquido IS NOT NULL)
